import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function rn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function np(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"np",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}
function rpn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rpn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  // === RN (100) ===
  rn("NCLEX-RN","Cardiovascular",3,"A client with takotsubo cardiomyopathy (stress cardiomyopathy) presents after severe emotional stress with chest pain and ST changes mimicking STEMI. The nurse should understand:",["This is always permanent cardiac damage","The LV dysfunction is typically reversible within days to weeks","Emergency CABG is always needed","This condition only affects men"],1,"Takotsubo (broken heart syndrome): transient LV apical ballooning triggered by emotional/physical stress, mimicking ACS. Coronary arteries are normal on angiography. Recovery occurs within days to weeks. More common in postmenopausal women. Supportive treatment with possible short-term HF medications."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with critical aortic stenosis is scheduled for transcatheter aortic valve replacement (TAVR). The nurse should teach:",["This is open-heart surgery","TAVR is a minimally invasive procedure performed through a catheter, typically via the femoral artery","No recovery period is needed","General anesthesia is always required"],1,"TAVR is an alternative to surgical AVR for high/intermediate risk patients. Catheter-based valve deployment through femoral artery (transfemoral approach) under moderate sedation or general anesthesia. Shorter recovery than surgical AVR. Monitor for vascular complications, stroke, and conduction abnormalities."),
  rn("RN-CAT","Cardiovascular",4,"A client with hypertrophic obstructive cardiomyopathy should avoid:",["ACE inhibitors","Dehydration, vasodilators, and vigorous exercise as these worsen the outflow tract obstruction","All physical activity permanently","Beta-blockers"],1,"HOCM: dynamic LVOT obstruction worsens with decreased preload (dehydration, Valsalva), decreased afterload (vasodilators), and increased contractility (exercise, digoxin). Avoid: dehydration, vigorous exercise, vasodilators (nitrates, diuretics). Beta-blockers and disopyramide reduce obstruction."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with constrictive pericarditis has Kussmaul sign. This is defined as:",["Falling blood pressure during inspiration","Paradoxical rise in jugular venous pressure during inspiration","Pulsus alternans","Wide pulse pressure"],1,"Kussmaul sign: JVP rises (or fails to fall) during inspiration. In constrictive pericarditis, the rigid pericardium prevents the heart from accommodating increased venous return during inspiration. Also seen in restrictive cardiomyopathy and right-sided heart failure."),
  rn("NCLEX-RN","Respiratory",3,"A client with cystic fibrosis develops Pseudomonas aeruginosa colonization. The nurse should understand:",["This is easily eradicated with short-course antibiotics","Chronic Pseudomonas colonization is common in CF and associated with accelerated lung function decline","Pseudomonas is harmless in CF","Only IV antibiotics are effective"],1,"Chronic Pseudomonas in CF: associated with increased morbidity, accelerated FEV1 decline, and reduced survival. Treatment: inhaled tobramycin (alternating months), inhaled aztreonam, and IV antibiotics during exacerbations. Aggressive early eradication attempts may delay chronic colonization."),
  rn("NCLEX-RN","Respiratory",3,"A client with community-acquired pneumonia severity is assessed using the CURB-65 score. This includes:",["Only temperature and heart rate","Confusion, Uremia (BUN > 20), Respiratory rate >= 30, Blood pressure < 90/60, and age >= 65","Only oxygen saturation","Only white blood cell count"],0,"CURB-65 guides site of care: 0-1 = outpatient, 2 = consider short inpatient stay or closely supervised outpatient, 3-5 = hospitalize (4-5 consider ICU). Each criterion is one point. PSI/PORT score is a more comprehensive alternative."),
  rn("NCLEX-RN","Respiratory",3,"A client with empyema (infected pleural effusion) requires:",["Antibiotics alone","Chest tube drainage plus IV antibiotics; video-assisted thoracoscopic surgery (VATS) for loculated empyema","Observation without drainage","Thoracentesis only"],1,"Empyema management: chest tube drainage (large bore or pigtail with fibrinolytics), IV antibiotics (cover common pathogens including anaerobes), and VATS for loculated or inadequately drained empyema. Early surgical intervention improves outcomes."),
  rn("NCLEX-RN","Neurological",3,"A client with a middle cerebral artery stroke on the dominant side will likely have:",["Only visual deficits","Contralateral hemiparesis (face and arm > leg), aphasia, and contralateral homonymous hemianopia","Bilateral lower extremity weakness","Cerebellar ataxia"],1,"Dominant hemisphere MCA stroke: contralateral hemiparesis (face and arm > leg), Broca aphasia (non-fluent, anterior) or Wernicke aphasia (fluent, posterior) or global, contralateral homonymous hemianopia, and contralateral hemisensory loss. Non-dominant: neglect, spatial inattention."),
  rn("NCLEX-RN","Neurological",3,"A client with trigeminal neuralgia describes electric shock-like pain in the face triggered by chewing. First-line treatment is:",["Opioid analgesics","Carbamazepine (anticonvulsant that reduces neuronal firing)","NSAIDs","Surgical intervention as first-line"],1,"Carbamazepine is first-line for trigeminal neuralgia (80% initial response rate). It stabilizes the neuronal membrane through sodium channel blockade. Monitor CBC (aplastic anemia/agranulocytosis risk) and LFTs. Oxcarbazepine is an alternative. Microvascular decompression is considered for refractory cases."),
  rn("NCLEX-RN","Neurological",3,"A client with a spinal cord injury at C4 requires:",["No respiratory assistance","Mechanical ventilation as the diaphragm (C3-C5 innervation) may be partially or fully compromised","Only supplemental oxygen","Chest physiotherapy alone"],1,"C4 SCI: diaphragm innervation (C3-C5) may be partially intact but compromised. Most C4 SCI patients require mechanical ventilation initially; some achieve ventilator weaning with phrenic nerve stimulation or diaphragm pacing. C3 and above: ventilator-dependent."),
  rn("NCLEX-RN","Endocrine",3,"A client with empty sella syndrome has which endocrine consequence?",["Always hyperfunction of the pituitary","Possible hypopituitarism requiring hormone replacement therapy","No endocrine effects","Only growth hormone excess"],1,"Empty sella: arachnoid herniation into the sella turcica compresses the pituitary. Most cases are incidental findings with normal pituitary function. Some develop partial hypopituitarism requiring screening for cortisol, thyroid, growth hormone, and gonadotropin deficiencies."),
  rn("NCLEX-RN","Endocrine",3,"A client with type 2 diabetes who is overweight should have which GLP-1 receptor agonist considered for both glycemic control and weight management?",["Insulin glargine","Semaglutide (Ozempic/Wegovy) which provides significant weight loss in addition to glucose lowering","Metformin alone","Glipizide"],1,"Semaglutide provides 15-17% weight loss (SELECT trial) in addition to HbA1c reduction of 1-1.5%. Cardiovascular benefit is established (SUSTAIN-6, SELECT). GI side effects are common initially. Weekly injection formulation improves adherence. Tirzepatide (GIP/GLP-1) provides even greater weight loss."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with esophageal perforation (Boerhaave syndrome) from forceful vomiting presents with:",["Mild dysphagia only","Severe chest pain, subcutaneous emphysema, and Hamman sign (mediastinal crunch)","Abdominal distension alone","Hematemesis only"],1,"Boerhaave syndrome: full-thickness esophageal rupture, usually from forceful vomiting. Mackler triad: vomiting, lower chest pain, and subcutaneous emphysema. Hamman sign (crunching on auscultation). High mortality without treatment. Emergency: IV antibiotics, NPO, surgical repair or endoscopic stenting."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with eosinophilic esophagitis has dysphagia and food impaction. The nurse should understand treatment includes:",["Only avoidance of spicy foods","Proton pump inhibitors, topical swallowed corticosteroids (fluticasone or budesonide), and dietary elimination","Antibiotics for infection","Surgical myotomy"],1,"EoE: chronic immune-mediated esophageal inflammation. Treatment: PPI trial (some respond), topical swallowed corticosteroids (fluticasone swallowed from MDI, budesonide slurry), six-food elimination diet, and dupilumab (FDA-approved for EoE). Endoscopic dilation for strictures."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with short bowel syndrome after massive small bowel resection is at risk for:",["Only vitamin deficiency","Malabsorption, dehydration, electrolyte imbalances, and parenteral nutrition dependence","Normal nutritional status with supplementation","Obesity from increased absorption"],1,"SBS (< 200 cm residual small bowel): severe malabsorption of macronutrients, fat-soluble vitamins, B12, minerals, and fluids. Initial TPN dependence with gradual enteral autonomy as adaptation occurs. Teduglutide (GLP-2 analogue) promotes mucosal growth and reduces TPN dependence."),
  rn("NCLEX-RN","Pharmacology",3,"A client on long-term proton pump inhibitor therapy should be counseled about potential risks including:",["No long-term risks exist","Increased risk of osteoporotic fractures, C. diff infection, hypomagnesemia, and vitamin B12 deficiency","Immediate bone loss","Cardiac arrest"],1,"Long-term PPI risks: osteoporotic fractures (decreased calcium absorption), C. diff infection, hypomagnesemia, vitamin B12 deficiency (decreased absorption), chronic kidney disease, and possible increased dementia risk (controversial). Periodic reevaluation of PPI necessity is recommended."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed naloxone for opioid overdose reversal should be monitored for:",["Only respiratory improvement","Acute opioid withdrawal syndrome and re-sedation when naloxone wears off","Permanent opioid receptor blockade","No monitoring needed after administration"],1,"Naloxone duration (30-90 minutes) is shorter than most opioids. Re-sedation can occur after naloxone wears off, requiring repeat dosing or continuous monitoring. Titrate to adequate respiration (not full alertness) to avoid precipitating acute withdrawal (hypertension, tachycardia, agitation, vomiting)."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving iron infusion (ferric carboxymaltose) should be monitored during administration for:",["Only injection site pain","Hypersensitivity reactions including anaphylaxis (rare but possible)","Hepatotoxicity","Renal failure"],1,"IV iron reactions range from minor (flushing, nausea, myalgias) to severe anaphylaxis (rare with newer formulations). Test dose is no longer routinely required for newer iron formulations. Monitor vital signs during and 30 minutes after infusion. Have emergency equipment available."),
  rn("NCLEX-RN","Mental Health",3,"A client with hoarding disorder should have treatment focus on:",["Forced cleanout of the home","Cognitive behavioral therapy specifically designed for hoarding with gradual discarding exercises","Medication as sole treatment","Immediate psychiatric hospitalization"],1,"Hoarding-specific CBT: motivational interviewing, cognitive restructuring (challenging attachment beliefs), graduated exposure (discarding exercises), organizational skills training, and acquisition reduction. Forced cleanout without therapy has high recidivism. SSRIs may reduce anxiety/depression comorbidity."),
  rn("NCLEX-RN","Mental Health",3,"A client with delirium tremens (alcohol withdrawal) should receive which medication as first-line treatment?",["Haloperidol","Benzodiazepines (chlordiazepoxide, lorazepam, or diazepam)","SSRIs","Beta-blockers alone"],1,"DT management: benzodiazepines are first-line (symptom-triggered using CIWA-Ar protocol preferred over fixed schedule). Lorazepam preferred in liver disease (no hepatic metabolism). Supportive care: IV thiamine BEFORE glucose, fluid resuscitation, electrolyte replacement, vital sign monitoring."),
  rn("NCLEX-RN","Pediatrics",3,"A child with developmental dysplasia of the hip detected at birth should be treated with:",["Full leg cast immediately","Pavlik harness (maintains flexion and abduction for hip reduction)","No treatment until the child is walking","Surgical open reduction as first-line"],1,"Pavlik harness: standard treatment for DDH in infants < 6 months. Maintains hips in flexion (100-110 degrees) and abduction (40-60 degrees). Worn full-time for 6-12 weeks. Success rate > 90% when initiated early. Follow-up ultrasound confirms reduction. Older infants may need closed or open reduction."),
  rn("NCLEX-RN","Pediatrics",3,"A child with nephrotic syndrome and edema should have the diet modified to include:",["High-sodium diet to replace losses","Normal sodium intake with adequate protein; sodium restriction during edema","Very low protein to reduce proteinuria","High-fat diet for energy"],1,"Nephrotic syndrome diet: normal protein intake (not low-protein as previously recommended, not high-protein to avoid hyperfiltration), sodium restriction during active edema (< 2g/day), and no fluid restriction unless hyponatremic. Monitor albumin, lipids, and renal function."),
  rn("NCLEX-RN","Pediatrics",3,"A child with acute rheumatic fever is diagnosed using the revised Jones criteria. Major manifestations include:",["Fever and elevated ESR only","Carditis, polyarthritis, chorea, erythema marginatum, and subcutaneous nodules","Sore throat and rash","Joint pain and headache"],0,"Revised Jones criteria: major (carditis, polyarthritis, Sydenham chorea, erythema marginatum, subcutaneous nodules) and minor (fever, arthralgia, elevated ESR/CRP, prolonged PR interval). Diagnosis: 2 major OR 1 major + 2 minor with evidence of preceding GAS infection."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with complete placenta previa should be managed with:",["Vaginal delivery attempt","Cesarean delivery scheduled at 36-37 weeks after antenatal corticosteroids","Induction of labor at term","Expectant management until 42 weeks"],1,"Complete previa: placenta covers the internal os entirely. Vaginal delivery is contraindicated. Scheduled cesarean at 36-37 weeks (after antenatal corticosteroids). Earlier delivery if significant bleeding occurs. Pelvic rest (no intercourse, digital exams) throughout pregnancy."),
  rn("NCLEX-RN","Maternal/Newborn",3,"The nurse should educate parents about safe sleep practices including:",["Co-sleeping is always safe","Alone, on the back, in a crib with a firm mattress and no loose bedding","Sleeping with stuffed animals for comfort","Side-lying position is preferred"],1,"ABCs of safe sleep: Alone (no bed-sharing), on the Back, in a Crib. Firm flat mattress, fitted sheet only, no blankets/pillows/bumpers/toys. Room-sharing (same room, separate surface) is recommended for the first 6-12 months. Pacifier at nap/bedtime is protective."),
  rn("NCLEX-RN","Renal",3,"A client with ADPKD should have blood pressure controlled to:",["140/90 or below","Target of < 130/80 (or < 110/75 in young patients with well-preserved GFR) to slow cyst growth and kidney function decline","No specific target","160/100 as acceptable"],1,"HALT-PKD trial: intensive BP control (< 110/75 in young patients with GFR > 60) slowed total kidney volume growth. ACEi/ARB are preferred (block RAAS). Tolvaptan (V2 receptor antagonist) is FDA-approved for rapidly progressive ADPKD. Adequate hydration and sodium restriction are important."),
  rn("NCLEX-RN","Infection Control",3,"A client with multidrug-resistant tuberculosis requires treatment with:",["Standard 4-drug regimen for 6 months","A specialized regimen lasting 18-24 months with second-line drugs (linezolid, bedaquiline, fluoroquinolones)","Single-drug therapy","No effective treatment exists"],1,"MDR-TB (resistant to INH and rifampin) requires prolonged treatment (18-24 months) with second-line drugs: bedaquiline, linezolid, fluoroquinolone, and others based on susceptibility. New shorter regimens (BPaL: bedaquiline, pretomanid, linezolid) show promise for highly resistant strains."),
  rn("NCLEX-RN","Hematological",3,"A client with beta-thalassemia major requires chronic transfusion therapy. The most important complication to monitor is:",["Infection from transfusions only","Iron overload (hemosiderosis) affecting the heart, liver, and endocrine organs","Mild anemia","Skin reactions only"],1,"Chronic transfusion causes iron accumulation (each unit contains 250mg iron). Iron deposits damage heart (cardiomyopathy - leading cause of death), liver (fibrosis/cirrhosis), and endocrine organs (diabetes, hypogonadism). Iron chelation (deferasirox, deferoxamine) is essential."),
  rn("NCLEX-RN","Immunological",3,"A client with dermatomyositis has a heliotrope rash and proximal muscle weakness. The nurse should understand that:",["Skin findings are unrelated to the disease","Dermatomyositis is associated with underlying malignancy in adults (cancer screening is recommended)","Only children are affected","No treatment is available"],1,"Dermatomyositis in adults is associated with underlying malignancy in 15-25% of cases (ovarian, lung, pancreatic, gastric, colorectal). Cancer screening is recommended at diagnosis and periodically. Treatment: corticosteroids and immunosuppressants. Monitor CK for disease activity."),
  rn("NCLEX-RN","Integumentary",3,"A client with a pressure injury should have the wound staged based on:",["Size alone","Depth of tissue damage: Stage 1 (non-blanchable erythema), Stage 2 (partial thickness), Stage 3 (full thickness), Stage 4 (exposed bone/tendon/muscle)","Color only","Patient age"],1,"NPUAP staging: Stage 1 = intact skin with non-blanchable erythema, Stage 2 = partial thickness (shallow ulcer/blister), Stage 3 = full thickness (fat visible, not bone/tendon), Stage 4 = full thickness with exposed bone/tendon/muscle. Unstageable = covered by eschar/slough. DTI = purple/maroon intact skin."),
  rn("RN-CAT","Critical Care",4,"A client with massive transfusion protocol activated should be monitored for:",["Only volume overload","Hypothermia, coagulopathy, and acidosis (lethal triad of trauma)","Allergic reactions only","Hyperkalemia alone"],1,"Massive transfusion lethal triad: hypothermia (cold blood products impair coagulation), coagulopathy (dilution and consumption of clotting factors), and acidosis (from hypoperfusion and citrate). Management: warm blood products, 1:1:1 ratio (RBC:FFP:platelets), calcium replacement, and damage control resuscitation."),
  rn("RN-CAT","Critical Care",3,"A client with acute kidney injury on continuous renal replacement therapy has a filter clotting frequently. The nurse should anticipate:",["Stopping CRRT permanently","Regional citrate anticoagulation or systemic heparin to maintain circuit patency","Increasing the blood flow rate alone","Changing the filter less frequently"],0,"CRRT filter clotting options: regional citrate anticoagulation (preferred - citrate chelates calcium in the circuit, calcium is replaced post-filter), systemic heparin (increased bleeding risk), or no anticoagulation with frequent saline flushes. Citrate anticoagulation is safer with less bleeding."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with Takayasu arteritis has diminished upper extremity pulses. This condition involves:",["Coronary artery disease","Large vessel vasculitis primarily affecting the aorta and its major branches","Peripheral neuropathy","Deep vein thrombosis"],1,"Takayasu arteritis: granulomatous inflammation of the aorta and its branches causing stenosis, occlusion, and aneurysms. Primarily affects young women. Pulseless disease (diminished arm pulses), BP discrepancies between arms, bruits, and claudication. Treatment: corticosteroids and immunosuppressants."),
  rn("NCLEX-RN","Respiratory",3,"A client with alpha-1 antitrypsin deficiency should be tested because:",["It causes asthma only","Deficiency leads to premature emphysema (especially in lower lobes) and may be treated with augmentation therapy","It is a common cause of pneumonia","It only affects elderly patients"],1,"Alpha-1 antitrypsin deficiency: autosomal co-dominant, causes early-onset emphysema (lower lobe predominant, unlike smoking-related upper lobe). Augmentation therapy (IV alpha-1 proteinase inhibitor weekly) slows lung function decline. Avoid smoking (dramatically accelerates disease)."),
  rn("NCLEX-RN","Neurological",3,"A client with posterior reversible encephalopathy syndrome (PRES) has severe hypertension, headache, visual changes, and seizures. MRI shows:",["Normal findings","Posterior white matter edema on FLAIR/T2 sequences (vasogenic edema)","Hemorrhagic infarction","Mass lesion"],1,"PRES: vasogenic edema primarily in posterior cerebral regions (parietal-occipital) from loss of cerebrovascular autoregulation. Causes: severe hypertension, eclampsia, immunosuppressants (tacrolimus, cyclosporine). Treatment: aggressive BP control and removing the cause. Usually reversible with prompt treatment."),
  rn("NCLEX-RN","Endocrine",3,"A client with a thyroid storm should have which immediate treatment priority?",["Radioactive iodine therapy","Beta-blocker (propranolol) for symptom control, followed by thionamide, iodine, and corticosteroids","Levothyroxine administration","Thyroidectomy immediately"],1,"Thyroid storm treatment sequence: beta-blocker (propranolol - also blocks T4-to-T3 conversion), thionamide (PTU preferred - blocks synthesis AND peripheral conversion), saturated iodine solution (given 1 hour after thionamide to block hormone release), corticosteroids (block T4-to-T3 conversion), and supportive care."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with autoimmune hepatitis has elevated liver enzymes and positive antinuclear antibodies. Treatment includes:",["Antivirals","Corticosteroids and azathioprine (immunosuppressive therapy)","Liver transplant as first-line","No treatment is effective"],1,"Autoimmune hepatitis treatment: prednisone induction (usually with azathioprine to reduce steroid dose) followed by azathioprine maintenance. Response rate > 80%. Treatment may be lifelong. Monitor for drug side effects, liver function, and disease remission (normal ALT and IgG)."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed direct oral anticoagulants should know that specific reversal agents exist for:",["No DOACs have reversal agents","Dabigatran (idarucizumab) and factor Xa inhibitors (andexanet alfa)","All DOACs use vitamin K for reversal","Only warfarin has a reversal agent"],1,"DOAC reversal: idarucizumab (Praxbind) specifically reverses dabigatran (monoclonal antibody fragment). Andexanet alfa (Andexxa) reverses factor Xa inhibitors (apixaban, rivaroxaban). For refractory bleeding, PCC (4-factor) may be used. These agents allow safe emergency reversal."),
  rn("NCLEX-RN","Mental Health",3,"A client with acute lithium toxicity (level 3.0 mEq/L) should receive:",["Oral fluid hydration only","Hemodialysis as lithium levels > 2.5 with toxicity symptoms require extracorporeal removal","Increased lithium dose","Activated charcoal"],1,"Lithium level > 2.5 with symptoms warrants hemodialysis (lithium's small molecular weight and lack of protein binding make it dialyzable). Severe symptoms include seizures, coma, cardiac arrhythmias, and renal failure. IV fluids and electrolyte correction are concurrent. Activated charcoal does not bind lithium."),
  rn("NCLEX-RN","Pediatrics",3,"A child with phenylketonuria should have which dietary restriction implemented immediately after diagnosis?",["Elimination of all protein","Strict phenylalanine restriction with specialized medical formula","Elimination of carbohydrates only","No dietary restrictions needed"],1,"PKU: phenylalanine hydroxylase deficiency causes toxic phenylalanine accumulation, causing intellectual disability if untreated. Lifelong low-phenylalanine diet: special medical formula, avoid high-protein foods (meat, dairy, eggs, nuts). Monitor blood phenylalanine levels regularly. Sapropterin (BH4) helps some patients."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client with amniotic fluid embolism develops sudden respiratory distress, hypotension, and DIC during labor. The nurse should:",["Administer oxytocin to speed delivery","Activate the emergency response team for aggressive cardiopulmonary support","Perform immediate vaginal delivery","Administer tocolytics"],1,"AFE: catastrophic obstetric emergency with 60-80% mortality. Management: immediate resuscitative efforts (intubation, mechanical ventilation, vasopressors, massive transfusion for DIC), emergency delivery if undelivered, ECMO for refractory cardiopulmonary failure. Survival depends on rapid response."),
  rn("NCLEX-RN","Renal",3,"A client on hemodialysis develops first-use syndrome during the first dialysis session. This is caused by:",["Volume depletion","Hypersensitivity reaction to the dialysis membrane or sterilizing agents","Electrolyte imbalance","Air embolism"],1,"First-use syndrome: complement activation or hypersensitivity to dialysis membranes (biocompatible membranes reduce risk) or sterilizing agents (ethylene oxide). Symptoms: chest pain, back pain, dyspnea, hypotension. Management: stop dialysis, treat symptomatically, and switch membrane type."),
  rn("NCLEX-RN","Hematological",3,"A client with hereditary spherocytosis has chronic hemolytic anemia and splenomegaly. The treatment of choice is:",["Iron supplementation","Splenectomy (removes the site of spherocyte destruction)","Bone marrow transplant","Corticosteroids"],1,"Hereditary spherocytosis: defective RBC membrane proteins cause sphere-shaped cells trapped and destroyed in the spleen. Splenectomy eliminates the primary site of hemolysis, improving anemia. Vaccinate against encapsulated organisms (pneumococcus, meningococcus, H. influenzae) before splenectomy."),
  rn("NCLEX-RN","Immunological",3,"A client with Behcet disease presents with the classic triad of:",["Fever, rash, and arthritis","Oral ulcers, genital ulcers, and ocular inflammation (uveitis)","Headache, photophobia, and neck stiffness","Joint pain, skin nodules, and kidney disease"],1,"Behcet disease: systemic vasculitis with classic triad of recurrent oral aphthous ulcers, genital ulcers, and uveitis. Also causes skin lesions, arthritis, CNS involvement, and GI ulceration. Treatment: colchicine for mucocutaneous, azathioprine for eyes, anti-TNF for severe disease."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with cardiac sarcoidosis should be monitored for:",["Only skin nodules","Conduction abnormalities, ventricular arrhythmias, and heart failure","No cardiac effects","Coronary artery disease only"],1,"Cardiac sarcoidosis: granulomatous infiltration causes conduction abnormalities (AV block most common), ventricular tachycardia (sudden death risk), and cardiomyopathy. Diagnosis: cardiac MRI (late gadolinium enhancement), PET scan, or biopsy. Treatment: corticosteroids, ICD for arrhythmia risk."),
  rn("NCLEX-RN","Respiratory",3,"A client with lymphangioleiomyomatosis (LAM) is a young woman presenting with recurrent pneumothorax. The nurse should understand:",["This is the same as COPD","LAM is a rare progressive cystic lung disease almost exclusively affecting women of childbearing age","This condition affects only elderly men","No treatment is available"],1,"LAM: progressive cystic lung destruction caused by abnormal smooth muscle cell proliferation. Almost exclusively affects women (estrogen-dependent). Features: recurrent pneumothorax, chylous effusions, and progressive dyspnea. Treatment: sirolimus (mTOR inhibitor) slows disease progression. Lung transplant for advanced disease."),
  rn("NCLEX-RN","Neurological",3,"A client with Bell palsy has sudden unilateral facial paralysis. The nurse should explain that:",["This is always permanent","Most cases (70-80%) resolve completely within 3-6 months with corticosteroid treatment","Surgery is required in all cases","This is caused by stroke"],0,"Bell palsy: acute unilateral lower motor neuron facial nerve (CN VII) palsy. Differentiating from stroke: Bell's affects the entire half of the face (including forehead), while stroke spares the forehead. Treatment: corticosteroids within 72 hours, eye protection, and possibly antivirals."),
  rn("NCLEX-RN","Endocrine",3,"A client with prolactinoma should be treated with:",["Surgery as first-line for all sizes","Dopamine agonists (cabergoline or bromocriptine) as first-line medical therapy","Radiation therapy","No treatment needed"],1,"Prolactinoma first-line: dopamine agonists (cabergoline preferred over bromocriptine for efficacy and tolerability). DA therapy reduces prolactin, shrinks tumor, and restores gonadal function. Surgery is reserved for medication-intolerant, resistant tumors, or apoplexy. Visual field monitoring for macroadenomas."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with bile acid malabsorption after ileal resection should be treated with:",["Antacids","Bile acid sequestrants (cholestyramine, colesevelam) to bind excess bile acids in the colon","Proton pump inhibitors","Antifungal therapy"],1,"Ileal resection (> 100 cm) disrupts bile acid reabsorption, causing bile acid diarrhea (cholerheic diarrhea). Bile acid sequestrants bind bile acids preventing colonic secretory diarrhea. Extensive resection may cause fat malabsorption (bile acid depletion) requiring medium-chain triglyceride supplementation."),
  rn("NCLEX-RN","Pharmacology",3,"A client receiving erythropoiesis-stimulating agents for anemia of CKD should have hemoglobin maintained at:",["Greater than 13 g/dL","10-11.5 g/dL (higher levels increase cardiovascular and thromboembolic risk)","Less than 8 g/dL","Greater than 14 g/dL for optimal function"],1,"ESA target Hgb 10-11.5 g/dL per KDIGO guidelines. Higher targets (> 13) increase stroke, MI, VTE, and mortality risk (CREATE, CHOIR, TREAT trials). Iron supplementation is needed concurrently (transferrin saturation > 20%, ferritin > 100). Avoid ESAs in active malignancy."),
  rn("NCLEX-RN","Mental Health",3,"A client with borderline personality disorder uses splitting as a defense mechanism. The nurse should respond by:",["Ignoring the behavior","Maintaining consistent boundaries with a unified treatment team approach","Agreeing with the client's perceptions of good/bad staff","Assigning different staff members each shift"],1,"Splitting (idealizing some staff while devaluing others) creates team conflict. Management: treatment team consistency, shared care plans, regular team communication, firm therapeutic boundaries, and dialectical behavior therapy (DBT). Staff consistency prevents manipulation and promotes therapeutic alliance."),
  rn("NCLEX-RN","Pediatrics",3,"An infant with pyloric stenosis presents with:",["Bilious vomiting","Projectile non-bilious vomiting, palpable olive-shaped mass, and metabolic alkalosis","Diarrhea and weight gain","Normal feeding pattern"],1,"Pyloric stenosis: hypertrophy of pyloric sphincter causing gastric outlet obstruction. Projectile non-bilious vomiting (milk-curd) after feeding, olive-shaped mass in RUQ, and hypochloremic hypokalemic metabolic alkalosis from HCl loss. Diagnosis: ultrasound. Treatment: pyloromyotomy (Ramstedt procedure)."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A pregnant client with systemic lupus erythematosus should be counseled about the risk of:",["No pregnancy complications","Neonatal lupus, preterm delivery, preeclampsia, and fetal growth restriction","Only joint pain during pregnancy","Improved lupus symptoms during pregnancy"],1,"SLE pregnancy risks: preeclampsia (especially with antiphospholipid antibodies), preterm delivery, IUGR, neonatal lupus (anti-Ro/SSA antibodies cross placenta causing rash, congenital heart block), and flare. Hydroxychloroquine continues during pregnancy (reduces flares and neonatal heart block)."),
  rn("NCLEX-RN","Renal",3,"A client with renal tubular acidosis type 1 (distal) has which characteristic laboratory finding?",["Metabolic alkalosis","Non-anion gap metabolic acidosis with inability to acidify urine below pH 5.3","Respiratory acidosis","Anion gap metabolic acidosis"],1,"Type 1 (distal) RTA: impaired H+ secretion in distal tubule. Urine pH remains > 5.3 despite systemic acidosis. Features: non-anion gap metabolic acidosis, hypokalemia, nephrolithiasis (calcium phosphate), and nephrocalcinosis. Treatment: sodium bicarbonate or potassium citrate supplementation."),
  rn("NCLEX-RN","Hematological",3,"A client with warm autoimmune hemolytic anemia (AIHA) has a positive direct Coombs test. First-line treatment is:",["Red blood cell transfusion only","Corticosteroids (prednisone) as first-line immunosuppression","Splenectomy immediately","No treatment needed"],1,"Warm AIHA: IgG antibodies cause extravascular hemolysis (spleen). Positive DAT (direct Coombs). First-line: corticosteroids (70-80% initial response). Second-line: rituximab or splenectomy. Transfusion is challenging (crossmatch difficulty) but given for symptomatic anemia. Monitor for reticulocyte response."),
  rn("NCLEX-RN","Immunological",3,"A client with hereditary angioedema should have which emergency medication available?",["Epinephrine auto-injector","C1-inhibitor concentrate, icatibant, or ecallantide (epinephrine and antihistamines are ineffective in HAE)","Oral antihistamines","IV corticosteroids"],1,"HAE is complement-mediated (bradykinin pathway), NOT histamine-mediated. Epinephrine, antihistamines, and steroids are INEFFECTIVE. Acute treatment: C1-INH concentrate (Berinert, Cinryze), icatibant (bradykinin B2 receptor antagonist), or ecallantide (kallikrein inhibitor). Prophylaxis: lanadelumab."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with hypertensive emergency (SBP > 180 with target organ damage) should have blood pressure reduced by:",["50% within the first hour","No more than 25% within the first hour, then gradually to 160/100 over 2-6 hours","Normalized to 120/80 within 30 minutes","No immediate treatment needed"],0,"Rapid normalization risks organ ischemia (watershed stroke, MI, renal failure). Reduce MAP by max 25% in the first hour, then toward 160/100 over 2-6 hours, then normal over 24-48 hours. IV medications: nicardipine, clevidipine, or nitroprusside with arterial line monitoring."),
  rn("NCLEX-RN","Respiratory",3,"A client with acute epiglottitis in an adult presents with:",["Barking cough and stridor","Severe sore throat, drooling, muffled voice, and sitting in a tripod position","Productive cough with green sputum","Gradual onset over 2 weeks"],1,"Adult epiglottitis: rapid-onset severe sore throat, odynophagia, drooling, muffled voice, stridor, and respiratory distress. Lateral neck X-ray: thumbprint sign. Management: airway management (intubation if needed), IV antibiotics (ceftriaxone + vancomycin), and corticosteroids."),
  rn("NCLEX-RN","Neurological",3,"A client with myotonic dystrophy has difficulty releasing the handshake grip. This myotonia is caused by:",["Joint stiffness","Delayed relaxation of skeletal muscle due to abnormal chloride or sodium channel function","Peripheral neuropathy","Cerebellar dysfunction"],1,"Myotonic dystrophy: autosomal dominant trinucleotide repeat disorder causing delayed muscle relaxation after contraction. Grip myotonia (unable to release grip) and percussion myotonia are characteristic. Also causes cataracts, cardiac conduction defects, endocrine abnormalities, and cognitive decline."),
  rn("NCLEX-RN","Endocrine",3,"A client with type 2 diabetes on metformin develops a GFR decline to 28 mL/min. The nurse should:",["Continue metformin at the same dose","Discontinue metformin as it is contraindicated when GFR falls below 30 mL/min","Double the metformin dose","Switch to insulin only"],1,"Metformin dosing by GFR: eGFR >= 45: no dose adjustment, eGFR 30-44: reduce dose (max 1000mg/day), reassess risk/benefit, eGFR < 30: contraindicated (lactic acidosis risk). Alternative agents: SGLT2 inhibitor (if eGFR > 20), DPP-4 inhibitors, insulin. GLP-1 RAs are generally safe but not cleared renally."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with hereditary hemochromatosis should have phlebotomy therapy to maintain:",["Ferritin at the normal upper limit","Ferritin levels of 50-100 ng/mL to prevent iron-related organ damage","Ferritin below 10 ng/mL","Hemoglobin of 8 g/dL"],1,"Phlebotomy is the mainstay of hemochromatosis treatment. Induction: weekly phlebotomy (500 mL each) until ferritin < 50 ng/mL. Maintenance: phlebotomy every 2-4 months to keep ferritin 50-100. Early treatment prevents organ damage (cirrhosis, cardiomyopathy, diabetes, arthropathy)."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed a TNF inhibitor should be educated to report which serious adverse effect immediately?",["Mild injection site redness","Signs of infection (fever, cough, weight loss) as TNF inhibitors increase infection risk including reactivation TB","Mild headache","Temporary hair thinning"],1,"TNF inhibitors increase infection risk: serious bacterial infections, reactivation TB (mandatory screening before starting), invasive fungal infections (histoplasmosis, coccidioidomycosis in endemic areas), and hepatitis B reactivation. Also: lymphoma risk (debated), demyelinating disease, and lupus-like syndrome."),
  rn("NCLEX-RN","Mental Health",3,"A client with serotonin syndrome (from drug interactions) presents with:",["Sedation and hypothermia","Agitation, hyperthermia, clonus, hyperreflexia, and diaphoresis","Bradycardia and constipation","No symptoms"],1,"Serotonin syndrome: excess serotonergic activity causes mental status changes (agitation, confusion), autonomic instability (hyperthermia, diaphoresis, tachycardia), and neuromuscular abnormalities (clonus, hyperreflexia, rigidity). Treatment: stop serotonergic drugs, cyproheptadine (serotonin antagonist), and supportive cooling."),
  rn("NCLEX-RN","Pediatrics",3,"A child with intussusception presents with:",["Continuous mild abdominal pain","Episodic colicky abdominal pain, currant jelly stools, and a sausage-shaped mass in the RUQ","Chronic diarrhea","Projectile vomiting"],1,"Intussusception: telescoping of one bowel segment into another (usually ileum into colon). Classic triad: episodic colicky pain (drawing up knees), currant jelly stools (blood/mucus), and sausage-shaped palpable mass. Diagnosis: ultrasound (target sign). Treatment: pneumatic or hydrostatic reduction; surgery if unsuccessful."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A client experiencing postpartum depression should be treated with:",["Only counseling without medication","SSRI therapy (sertraline is preferred for breastfeeding compatibility) combined with psychotherapy","Benzodiazepines long-term","No treatment as it will resolve spontaneously"],1,"PPD treatment: SSRIs (sertraline has lowest breast milk transfer) combined with interpersonal therapy or CBT. Edinburgh Postnatal Depression Scale for screening. Brexanolone IV (allopregnanolone analogue) or zuranolone (oral) for moderate-severe PPD. Safety assessment for suicidality and infanticidal thoughts is critical."),
  rn("NCLEX-RN","Renal",3,"A client with oxalate nephropathy should be counseled to:",["Increase spinach and rhubarb intake","Limit high-oxalate foods (spinach, rhubarb, nuts, chocolate) and maintain adequate calcium and fluid intake","Avoid all dairy products","Restrict protein intake only"],1,"Oxalate nephropathy prevention: limit high-oxalate foods, adequate calcium intake WITH meals (calcium binds oxalate in the gut reducing absorption), high fluid intake (> 2.5 L/day), potassium citrate (alkalinizes urine), and vitamin B6 supplementation (reduces oxalate production)."),
  rn("NCLEX-RN","Hematological",3,"A client with chronic myeloid leukemia who achieves a deep molecular response on tyrosine kinase inhibitor therapy should know:",["TKI therapy is short-term only","Treatment-free remission (TFR) may be attempted with close molecular monitoring if deep response is sustained","No monitoring is needed after response","The disease is cured permanently"],1,"TKI discontinuation trials show 40-60% of CML patients with sustained deep molecular response (MR4 or better for >= 2 years) can attempt TFR. Requires intensive molecular monitoring (monthly for 6 months, then every 6-12 weeks). Restart TKI immediately if molecular recurrence occurs (almost always responsive)."),
  rn("NCLEX-RN","Immunological",3,"A client with IgG4-related disease has organ swelling and elevated serum IgG4. The nurse should anticipate treatment with:",["Antibiotics","Corticosteroids and rituximab for IgG4-RD","Antihistamines","No treatment needed"],1,"IgG4-RD: fibro-inflammatory condition affecting multiple organs (pancreas, salivary glands, orbits, kidneys, lungs). Elevated serum IgG4. Treatment: corticosteroids (dramatic initial response), rituximab for relapsing or steroid-dependent disease. Can mimic malignancy, requiring biopsy for diagnosis."),
  rn("RN-CAT","Critical Care",4,"A client with abdominal compartment syndrome has an intra-abdominal pressure of 28 mmHg with organ dysfunction. The nurse should prepare for:",["Conservative management only","Emergent surgical decompressive laparotomy","Increased IV fluids without other intervention","Discharge planning"],1,"ACS (IAP > 20 with organ dysfunction): decompressive laparotomy is the definitive treatment. Temporary abdominal closure (negative pressure wound therapy) is used to prevent re-development. Monitor: IAP via bladder pressure measurement, urine output, and hemodynamics. Risk: reperfusion injury after decompression."),
  rn("NCLEX-RN","Cardiovascular",3,"A client with right ventricular MI should receive which modification to standard STEMI management?",["No modification needed","Avoid nitroglycerin and diuretics as these reduce preload; aggressive IV fluids are needed","Administer nitroglycerin immediately","Restrict IV fluids"],1,"RV MI is preload-dependent. Nitrates and diuretics reduce preload, potentially causing severe hypotension. Treatment: IV fluid boluses (NS) to maintain adequate RV preload, avoid morphine (venodilation), and avoid diuretics. Dobutamine if fluids alone are insufficient. Reperfusion is the definitive treatment."),
  rn("NCLEX-RN","Respiratory",3,"A client with exercise-induced bronchoconstriction should use:",["Long-acting beta-agonist alone daily","Short-acting beta-agonist (albuterol) 15-30 minutes before exercise","Oral steroids before each exercise session","No medication is effective"],1,"EIB management: SABA (albuterol) 15-30 minutes pre-exercise provides 2-4 hours of protection. For frequent EIB: daily ICS (reduces airway inflammation underlying EIB). Warm-up exercise, face mask in cold weather, and montelukast are additional strategies. Rule out underlying persistent asthma."),
  rn("NCLEX-RN","Neurological",3,"A client with cerebral venous sinus thrombosis presents with headache and papilledema. Treatment includes:",["Observation without anticoagulation","Anticoagulation with heparin even in the presence of hemorrhagic infarction","Thrombolytic therapy for all cases","Surgical thrombectomy as first-line"],1,"CVST treatment: anticoagulation with heparin (UFH or LMWH) is first-line, even with hemorrhagic infarction (the hemorrhage is from venous congestion, and anticoagulation improves outflow). Followed by oral anticoagulation for 3-12 months. Endovascular thrombolysis for severe, progressive cases."),
  rn("NCLEX-RN","Endocrine",3,"A client with MEN type 1 should be screened for tumors of the:",["Thyroid only","Parathyroid (primary hyperparathyroidism), anterior pituitary (prolactinoma), and pancreatic islet cells (gastrinoma)","Adrenal glands only","Ovaries"],1,"MEN1 (Wermer syndrome): 3 Ps - Parathyroid (95%, primary hyperPTH), Pituitary (prolactinoma most common), Pancreas (gastrinoma/ZES most common, insulinoma). Autosomal dominant menin gene mutation. Regular biochemical and imaging surveillance throughout life."),
  rn("NCLEX-RN","Gastrointestinal",3,"A client with C. diff infection should be treated based on severity. For an initial non-severe episode, the preferred treatment is:",["Metronidazole","Fidaxomicin or vancomycin oral (IDSA 2021 guidelines prefer fidaxomicin)","IV vancomycin","Fecal transplant as first-line"],1,"IDSA 2021 C. diff guidelines: initial non-severe: fidaxomicin (preferred, lower recurrence) or oral vancomycin 125mg QID x 10 days. Metronidazole is now reserved only if fidaxomicin and vancomycin are unavailable. Severe/fulminant: high-dose vancomycin +/- IV metronidazole."),
  rn("NCLEX-RN","Mental Health",3,"A nurse should understand that psychological first aid after a disaster includes:",["Immediately debriefing all survivors about their experiences","Providing safety, calm, connectedness, self-efficacy, and hope (Hobfoll's five principles)","Forcing survivors to talk about the event","Prescribing medications to all survivors"],1,"PFA principles: promote safety (physical and psychological), calming (normalize stress responses), self and community efficacy (empowerment), connectedness (social support), and hope. Critical incident stress debriefing (forced discussion) is no longer recommended as it may increase PTSD risk."),
  rn("NCLEX-RN","Pediatrics",3,"A child with febrile seizures should have parents taught that:",["Febrile seizures always cause brain damage","Simple febrile seizures (< 15 minutes, generalized, single episode in 24 hours) have an excellent prognosis with no increased epilepsy risk","All children with febrile seizures need daily anticonvulsants","Lumbar puncture is always needed"],1,"Simple febrile seizures: benign, self-limited, no increased risk of epilepsy or brain damage, no long-term treatment needed. Complex febrile seizures (focal, prolonged, or multiple in 24 hours) require further evaluation. Teach parents seizure management: protect from injury, do not restrain, time the seizure, seek medical attention."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A newborn with respiratory distress syndrome (surfactant deficiency) should receive:",["Only oxygen supplementation","Exogenous surfactant replacement therapy via endotracheal tube","Inhaled bronchodilators","Oral corticosteroids"],1,"RDS treatment: exogenous surfactant (given via ET tube within 2 hours of birth) reduces surface tension, improves lung compliance, and reduces mortality. CPAP for mild cases. Antenatal corticosteroids (betamethasone) given to mothers in preterm labor significantly accelerate fetal lung maturity."),
  rn("NCLEX-RN","Renal",3,"A client with lithium-induced nephrogenic diabetes insipidus should be treated with:",["More lithium","Amiloride (blocks ENaC in collecting duct, reducing lithium uptake) and thiazide diuretics","DDAVP alone","Fluid restriction"],1,"Lithium-induced NDI: amiloride blocks lithium entry through ENaC channels in the collecting duct, reducing lithium's toxic effect on aquaporin-2. Thiazide diuretics paradoxically reduce urine volume by increasing proximal reabsorption. DDAVP is ineffective in nephrogenic DI."),
  rn("NCLEX-RN","Cardiovascular",3,"A client receiving a blood transfusion develops transfusion-related acute lung injury (TRALI). The nurse should:",["Continue the transfusion at a slower rate","Stop the transfusion immediately and provide supportive respiratory care","Administer diuretics for pulmonary edema","Restart the transfusion with a new filter"],1,"TRALI: acute hypoxemic respiratory distress within 6 hours of transfusion (anti-HLA or anti-granulocyte antibodies in donor plasma). Bilateral infiltrates on CXR. Treatment: stop transfusion, supportive care (oxygen, possible mechanical ventilation). Unlike TACO, diuretics are NOT helpful. Usually resolves within 48-72 hours."),
  rn("NCLEX-RN","Respiratory",3,"A client with idiopathic pulmonary fibrosis should be prescribed:",["Inhaled corticosteroids","Antifibrotic therapy (pirfenidone or nintedanib) to slow disease progression","Bronchodilators as primary treatment","Antibiotics"],1,"IPF treatment: antifibrotics (pirfenidone, nintedanib) slow FVC decline by approximately 50%. Corticosteroids and immunosuppressants are NOT effective and may be harmful (PANTHER-IPF trial). Supplemental oxygen for hypoxemia. Pulmonary rehabilitation. Lung transplant for advanced disease."),
  rn("NCLEX-RN","Neurological",3,"A client with a vestibular schwannoma (acoustic neuroma) has unilateral hearing loss, tinnitus, and imbalance. The nurse should:",["Reassure and discharge","Anticipate MRI for diagnosis and discuss treatment options (observation, surgery, or stereotactic radiosurgery)","Obtain a CT scan only","Administer antibiotics for ear infection"],1,"Acoustic neuroma (vestibular schwannoma): benign CN VIII tumor. Unilateral sensorineural hearing loss, tinnitus, and vestibular dysfunction. MRI with gadolinium is diagnostic. Management depends on size and symptoms: observation with serial MRI (small tumors), microsurgery, or stereotactic radiosurgery (Gamma Knife)."),
  rn("NCLEX-RN","Pharmacology",3,"A client prescribed checkpoint inhibitor immunotherapy for cancer should be monitored for:",["Only fatigue","Immune-related adverse events affecting any organ system (colitis, pneumonitis, hepatitis, endocrinopathies, dermatitis)","No significant side effects","Only GI symptoms"],1,"Checkpoint inhibitors (pembrolizumab, nivolumab, ipilimumab) unleash the immune system against cancer but can cause irAEs in any organ. Most common: dermatitis, colitis, hepatitis, pneumonitis, and endocrinopathies (thyroiditis, hypophysitis, adrenalitis, T1DM). Treatment: corticosteroids, possibly hold immunotherapy."),
  rn("NCLEX-RN","Mental Health",3,"Neuroleptic malignant syndrome (NMS) differs from serotonin syndrome in that NMS:",["Has rapid onset","Has gradual onset over days, lead-pipe rigidity, and bradyreflexia (compared to SS's acute onset and hyperreflexia)","Causes diarrhea","Is associated with SSRIs"],1,"NMS vs SS: NMS (antipsychotics) = gradual onset, lead-pipe rigidity, bradyreflexia, stable vital signs initially. SS (serotonergic drugs) = rapid onset, clonus/hyperreflexia, agitation, GI symptoms. Both: hyperthermia, altered mental status. NMS treatment: dantrolene, bromocriptine. SS: cyproheptadine."),
  rn("NCLEX-RN","Pediatrics",3,"A child with patent ductus arteriosus has a continuous machinery-like murmur best heard at:",["The apex","The left upper sternal border (left infraclavicular area)","The right lower sternal border","The aortic area"],1,"PDA murmur: continuous (systolic and diastolic) machinery-like murmur best heard at the left upper sternal border or left infraclavicular area. The ductus connects the pulmonary artery to the aorta. Treatment: indomethacin/ibuprofen (closes the ductus in premature infants) or surgical/catheter closure."),
  rn("NCLEX-RN","Maternal/Newborn",3,"A neonate born to a mother with poorly controlled diabetes should be monitored closely for:",["Hyperglycemia","Hypoglycemia within the first 1-2 hours of life","Hyperthermia","Excessive weight loss"],1,"Infants of diabetic mothers: fetal hyperinsulinemia (from maternal hyperglycemia) continues after birth despite sudden loss of maternal glucose supply, causing neonatal hypoglycemia. Monitor glucose within 30-60 minutes of birth. Other risks: macrosomia, respiratory distress, hypocalcemia, polycythemia."),
  rn("NCLEX-RN","Renal",3,"A client presenting with flank pain, hematuria, and a palpable abdominal mass should be evaluated for:",["Simple renal cyst","Renal cell carcinoma (classic triad, though present in only 10% of patients)","Urinary tract infection","Benign prostatic hyperplasia"],1,"RCC classic triad (hematuria, flank pain, palpable mass) occurs in only 10% of patients. Many are found incidentally on imaging. Other features: weight loss, paraneoplastic syndromes (polycythemia from erythropoietin, hypercalcemia from PTHrP). CT abdomen/pelvis with contrast is the staging study."),

  // === NP (30) ===
  np("AANP","Cardiovascular",3,"A patient with new-onset syncope should have which initial evaluation?",["Only brain imaging","ECG, orthostatic vital signs, and focused history and physical examination","Cardiac catheterization immediately","No workup for a single episode"],1,"Syncope evaluation: detailed history (prodrome, position, triggers), physical exam (orthostatic vitals, cardiac auscultation), and 12-lead ECG (arrhythmias, conduction disease, WPW, long QT, Brugada). Further testing based on risk stratification: echocardiogram, Holter/event monitor, or tilt table test."),
  np("AANP","Respiratory",3,"A patient with chronic cough on ACE inhibitor therapy should have the NP:",["Increase the ACE inhibitor dose","Switch to an ARB (ACEi cough occurs in 5-20% of patients and resolves within 1-4 weeks of stopping)","Add cough suppressant while continuing ACEi","Ignore the cough as it will resolve spontaneously"],1,"ACEi cough: dry, persistent, non-productive cough from bradykinin accumulation. Occurs in 5-20% of patients (more common in women and Asians). Resolves 1-4 weeks after discontinuation. Switch to ARB (does not cause bradykinin accumulation). Do not rechallenege with another ACEi."),
  np("NP-CAT","Neurological",3,"A patient with suspected normal pressure hydrocephalus should have which diagnostic and therapeutic procedure?",["CT scan only","Large-volume lumbar puncture (tap test) to assess gait improvement after CSF removal","Brain biopsy","EEG"],1,"NPH diagnosis: clinical triad + ventriculomegaly on imaging disproportionate to cerebral atrophy. Large-volume LP (30-50 mL CSF removal) with pre/post gait assessment is diagnostic: gait improvement predicts VP shunt response. Gait improves first and most consistently after shunting."),
  np("AANP","Endocrine",3,"A patient with diabetes and an HbA1c target of < 7% has a current level of 8.5% on metformin alone. The NP should:",["Continue metformin alone and recheck in 1 year","Add a second agent considering cardiovascular and renal comorbidities (SGLT2i or GLP-1 RA preferred if ASCVD or CKD)","Switch to sulfonylurea monotherapy","Start insulin immediately"],1,"ADA guidelines: if HbA1c target not met on metformin alone, add second agent based on patient factors. With established ASCVD or CKD: SGLT2 inhibitor or GLP-1 RA (proven cardiovascular/renal benefits). Without: consider cost, weight effects, hypoglycemia risk, and patient preference."),
  np("AANP","Gastrointestinal",3,"A patient with newly diagnosed celiac disease should be tested for:",["No additional conditions","Thyroid disease, type 1 diabetes, iron/folate/B12 deficiency, and bone density","HIV","Liver cancer"],1,"Celiac disease screening at diagnosis: thyroid function (autoimmune thyroiditis association), glucose/HbA1c (T1DM), iron studies, folate, B12, vitamin D, calcium, liver function, and DEXA scan (osteoporosis from malabsorption). First-degree relatives should be screened serologically."),
  np("NP-CAT","Pharmacology",4,"A patient requiring anticoagulation who has severe renal impairment (CrCl < 15 mL/min) should receive:",["Any DOAC at standard dose","Warfarin (DOACs have varying renal clearance and limited data in severe CKD/dialysis)","Aspirin alone","No anticoagulation"],1,"DOACs rely on renal clearance (dabigatran 80%, rivaroxaban 33%, apixaban 27%, edoxaban 50%). Severe CKD/dialysis: warfarin is the standard choice (does not require renal clearance). Apixaban has emerging data supporting use in ESRD but is not yet universally recommended."),
  np("AANP","Mental Health",3,"A patient with insomnia who also has depression should be prescribed:",["Benzodiazepines long-term","Mirtazapine or trazodone (antidepressants with sedating properties that address both conditions)","Stimulant medication","Caffeine reduction as sole treatment"],1,"Dual-purpose prescribing: mirtazapine (tetracyclic, sedating, appetite-stimulating - helpful for underweight depressed patients) or trazodone (serotonin antagonist/reuptake inhibitor, sedating at low doses). Avoid benzodiazepines long-term. CBT-I should be offered concurrently for the insomnia component."),
  np("AANP","Dermatology",3,"A patient with seborrheic dermatitis affecting the scalp should use:",["Oral antifungals as first-line","Medicated shampoos containing ketoconazole, selenium sulfide, or zinc pyrithione","Systemic corticosteroids","Topical antibiotics"],1,"Seborrheic dermatitis: antifungal shampoos (ketoconazole 2%, selenium sulfide, zinc pyrithione, ciclopirox) are first-line for scalp disease. Apply 5 minutes before rinsing. Topical corticosteroids (low-potency for face) for flares. Maintenance therapy prevents recurrence. Tacrolimus/pimecrolimus for facial disease."),
  np("AANP","Musculoskeletal",3,"A patient presenting with inflammatory low back pain (worse in morning, improves with exercise) should be evaluated for:",["Mechanical back pain only","Ankylosing spondylitis or axial spondyloarthropathy","Disk herniation","Spinal stenosis"],1,"Inflammatory back pain characteristics: onset < 40 years, insidious onset, morning stiffness > 30 minutes, improves with exercise, does not improve with rest, alternating buttock pain. Workup: HLA-B27, ESR/CRP, sacroiliac joint X-ray/MRI. Treatment: NSAIDs first-line, then TNF inhibitors or IL-17 inhibitors."),
  np("AANP","Infectious Disease",3,"A patient with mononucleosis should be counseled to avoid:",["All physical activity for 6 months","Contact sports for at least 3-4 weeks due to risk of splenic rupture","Going outdoors","All social contact"],1,"EBV mononucleosis causes splenomegaly (50-60% of cases). Contact sports, heavy lifting, and strenuous activity should be avoided for at least 3-4 weeks (some recommend until spleen returns to normal on ultrasound) to prevent traumatic splenic rupture, a potentially fatal complication."),
  np("AANP","Geriatrics",3,"Polypharmacy in the elderly is defined as concurrent use of:",["More than 2 medications","5 or more medications, increasing adverse drug reaction risk","Any number of medications","Exactly 10 medications"],1,"Polypharmacy (>= 5 medications) exponentially increases ADR risk, drug interactions, falls, cognitive impairment, and non-adherence. Management: comprehensive medication review, deprescribing low-value medications, identifying potentially inappropriate medications (Beers Criteria), and prioritizing patient goals of care."),
  np("NP-CAT","Reproductive",3,"A patient with suspected ectopic pregnancy and an hCG of 1500 IU/L should have:",["Abdominal ultrasound only","Transvaginal ultrasound (discriminatory zone is hCG 1500-2000 on TVUS)","No imaging until hCG is > 5000","MRI of the pelvis"],1,"The discriminatory zone (hCG level at which an intrauterine pregnancy should be visible on TVUS) is 1500-2000 IU/L. If TVUS shows no intrauterine pregnancy at hCG > discriminatory zone, ectopic pregnancy is highly suspected. Serial hCG trending (should increase > 35% in 48 hours for viable IUP) aids diagnosis."),
  np("AANP","Women's Health",3,"A patient with a LSIL (low-grade squamous intraepithelial lesion) Pap result should have:",["Immediate LEEP procedure","Repeat co-testing in 1 year for women aged 25-65, or colposcopy for women aged 21-24","No follow-up needed","Hysterectomy"],0,"ASCCP management guidelines for LSIL: age 25-65: HPV testing (if not done with Pap); if HPV positive or unknown, colposcopy; if HPV negative, repeat co-testing in 1 year. Age 21-24: repeat cytology in 12 months (higher regression rate in young women). Serial negative results return to routine screening."),
  np("NP-CAT","Hematological",3,"A patient with suspected hemophilia A should have which diagnostic test?",["Platelet count","Factor VIII level and aPTT (prolonged aPTT with normal PT, platelet count, and bleeding time)","PT/INR","D-dimer"],1,"Hemophilia A: factor VIII deficiency (X-linked recessive, affects males). Prolonged aPTT with normal PT, platelets, and bleeding time. Factor VIII level determines severity: mild (5-40%), moderate (1-5%), severe (< 1%). Treatment: factor VIII replacement (recombinant preferred), desmopressin for mild cases, emicizumab prophylaxis."),
  np("AANP","Renal",3,"A patient with recurrent calcium oxalate kidney stones should be counseled to:",["Restrict calcium intake","Maintain adequate dietary calcium, increase fluid intake > 2.5L/day, and reduce sodium and animal protein","Eliminate all vegetables","Take vitamin C supplements"],1,"Paradoxically, dietary calcium restriction INCREASES stone risk (less calcium binds oxalate in the gut, more oxalate absorbed). Recommendations: adequate dietary calcium, high fluid intake (urine output > 2.5L/day), reduced sodium (< 2g/day), reduced animal protein, and potassium citrate supplementation."),
  np("AANP","Ophthalmology",3,"A patient with diabetic retinopathy screening should have dilated eye exams:",["Only when visual symptoms develop","At diagnosis of T2DM, within 5 years of T1DM diagnosis, then annually","Every 5 years","Only after age 65"],1,"Screening timeline: T2DM: at diagnosis (may have had undiagnosed disease for years). T1DM: within 5 years of diagnosis (retinopathy rare before then). Then annually for both. Less frequent (every 2 years) if no retinopathy on previous exams. More frequent for advanced retinopathy."),
  np("AANP","Preventive Medicine",2,"The NP should recommend depression screening using:",["PHQ-9 for all adults as part of routine care (USPSTF recommendation)","Only when patients report symptoms","PHQ-9 only for elderly patients","Beck Depression Inventory exclusively"],0,"USPSTF recommends screening all adults for depression using validated tools (PHQ-2 initially, PHQ-9 if positive). Screening should be implemented with adequate systems for diagnosis, treatment, and follow-up. Screening in pregnancy and postpartum is also recommended (Edinburgh scale)."),
  np("AANP","Cardiovascular",3,"A patient with chronic venous insufficiency and leg ulcers should be treated with:",["Compression therapy only if arterial disease is ruled out first","Compression therapy (graduated compression stockings or wraps) as the cornerstone of treatment","Elevation only","Topical antibiotics as sole treatment"],0,"Venous ulcer management: compression therapy (30-40 mmHg) is essential (must first rule out significant PAD - ABI >= 0.8). Moist wound care, elevation, exercise (calf pump activation), and pentoxifylline or micronized purified flavonoid fraction may help healing. Treat underlying venous reflux."),
  np("AANP","Respiratory",3,"A patient with eosinophilic asthma not controlled on standard therapy should be considered for:",["Only higher-dose ICS","Biologic therapy targeting the type 2 inflammatory pathway (anti-IL5, anti-IL4/13, or anti-IgE)","Theophylline as primary treatment","Long-term oral corticosteroids"],1,"Severe eosinophilic asthma biologics: anti-IL5/IL5R (mepolizumab, reslizumab, benralizumab) for blood eosinophils >= 300, anti-IL4R (dupilumab) for T2-high asthma, anti-IgE (omalizumab) for allergic asthma. Reduce exacerbations, improve lung function, and allow steroid tapering."),
  np("NP-CAT","Endocrine",3,"A patient with adrenal incidentaloma (found incidentally on imaging) should be evaluated for:",["No evaluation needed for all incidentalomas","Hormone excess (cortisol, catecholamines, aldosterone) and malignancy potential based on imaging characteristics","Immediate surgical removal","Only repeat imaging in 5 years"],1,"Adrenal incidentaloma workup: functional assessment (1mg DST for cortisol excess, plasma metanephrines for pheo, aldosterone/renin ratio if hypertensive) and malignancy risk assessment (size > 4cm, CT characteristics - washout, HU). Surgery for functional tumors or suspicious for malignancy."),

  // === RPN (35) ===
  rpn("REX-PN","Cardiovascular",2,"A client with peripheral vascular disease should be taught to:",["Soak feet in hot water for circulation","Inspect feet daily for injuries, keep feet clean and dry, and wear properly fitting shoes","Walk barefoot for better circulation","Apply heating pads to the feet"],1,"PVD foot care: daily inspection (including between toes), wash and dry thoroughly, moisturize (not between toes), wear properly fitting shoes and clean cotton socks, avoid extreme temperatures, cut toenails straight across, and report any injuries or changes immediately. Prevents ulceration and amputation."),
  rpn("REX-PN","Respiratory",2,"A client using oxygen at home should be taught that the primary safety concern is:",["Oxygen is explosive","Oxygen supports combustion; keep away from open flames, smoking materials, and heat sources","Oxygen has no safety concerns","Oxygen causes immediate toxicity"],1,"Oxygen itself does not explode but greatly supports combustion. Safety rules: no smoking near oxygen, keep 6-10 feet from heat/flames, use cotton clothing (avoid static), post 'Oxygen in Use' signs, store cylinders properly, and keep a fire extinguisher accessible."),
  rpn("RPN-CAT","Neurological",3,"A client with seizures should have the nurse ensure safety during the seizure by:",["Restraining the client and inserting a tongue blade","Protecting the head, clearing the area, turning to side when safe, timing the seizure, and not restraining","Calling security to hold the client down","Administering oral medications immediately"],1,"Seizure safety: protect head (place padding underneath), clear surrounding hazards, do NOT restrain or insert anything in the mouth, turn to the side after convulsions stop (prevent aspiration), time the seizure, note characteristics, and stay with the client. Call for help if > 5 minutes."),
  rpn("REX-PN","Endocrine",2,"A client with diabetes who exercises regularly should be taught to:",["Skip meals before exercising","Carry a fast-acting carbohydrate source during exercise in case of hypoglycemia","Avoid all physical activity","Increase insulin dose before each exercise session"],1,"Exercise lowers blood glucose by increasing insulin sensitivity and glucose utilization. Carry fast-acting carbs (glucose tablets, juice). Check blood glucose before exercise: < 100 = eat snack, 100-250 = safe to exercise, > 250 with ketones = do not exercise. Adjust insulin/food based on activity."),
  rpn("REX-PN","Gastrointestinal",2,"A client with a colostomy in the ascending colon should expect the output to be:",["Formed, solid stool","Liquid to semi-liquid consistency due to less water absorption in the ascending colon","No output expected","Large, formed stools"],1,"Stool consistency depends on colostomy location: ascending colon = liquid/semi-liquid (minimal water absorption), transverse = semi-formed, descending/sigmoid = formed (most water absorbed). Ascending colostomy requires more careful skin protection due to liquid, enzymatic effluent."),
  rpn("REX-PN","Pharmacology",2,"Before administering a medication, a nurse notices the client has a medication allergy band. The nurse should:",["Administer the medication and document the allergy","Verify the specific allergy and cross-check with the prescribed medication before administration","Remove the allergy band to administer the medication","Ignore the band if the client does not mention it"],1,"Verify specific allergen (drug name, reaction type) and cross-reference with prescribed medications. Check for cross-reactivity (e.g., penicillin-cephalosporin). Document findings. If allergy matches or cross-reacts, hold the medication and notify the prescriber for an alternative."),
  rpn("REX-PN","Mental Health",2,"When a client expresses suicidal ideation, the nurse should first:",["Leave the client alone to calm down","Directly ask about a specific plan, intent, and means to assess suicide risk","Change the subject to avoid upsetting the client","Call the family immediately"],1,"Direct assessment: asking about suicide does NOT increase risk. Assess: ideation (passive vs. active), plan (specific method, timeline), intent (desire to act), means (access to lethal means), and protective factors. Stay with the client, ensure safety, and notify the treatment team immediately."),
  rpn("REX-PN","Pediatrics",2,"When measuring the head circumference of an infant, the nurse should:",["Measure across the forehead only","Place the tape measure around the largest circumference (above the eyebrows and around the occipital prominence)","Use a rigid ruler","Estimate based on visual inspection"],1,"Head circumference: measure the largest occipitofrontal circumference (tape above the eyebrows and ears, around the occipital prominence). Measure 3 times and record the largest. Plot on growth chart. Abnormal: microcephaly (< 2 SD below mean) or macrocephaly (> 2 SD above mean)."),
  rpn("REX-PN","Fundamentals",2,"A client refusing a blood transfusion based on religious beliefs (Jehovah's Witness) has the right to:",["Be overridden by the medical team's decision","Refuse the transfusion based on autonomy and informed consent","Have the nurse administer it anyway in an emergency","Be discharged immediately"],1,"Patient autonomy is a fundamental ethical principle. Competent adults have the right to refuse any treatment, including life-saving blood transfusions, based on religious or personal beliefs. Document the refusal, ensure informed consent (understanding risks), and explore alternative treatments."),
  rpn("REX-PN","Musculoskeletal",2,"A client with a hip replacement should avoid:",["Walking with a walker","Hip flexion greater than 90 degrees, internal rotation, and adduction past midline","All movement of the affected leg","Sitting in a chair with armrests"],1,"Hip replacement precautions (posterior approach): avoid > 90 degree hip flexion, avoid internal rotation, avoid crossing legs (adduction past midline). Use elevated toilet seat, avoid low chairs, and use a reacher for shoes/socks. These prevent prosthetic dislocation."),
  rpn("REX-PN","Renal",2,"A client with a nephrostomy tube should have the tube care include:",["Clamping the tube routinely","Never clamping the tube without a provider order, as obstruction can cause hydronephrosis","Irrigating the tube with tap water","Removing the tube when drainage decreases"],1,"Nephrostomy tube care: never clamp (obstruction increases renal pressure causing hydronephrosis and infection), keep the drainage bag below kidney level, monitor output (report decreased output), clean exit site daily, secure the tube to prevent dislodgement, and report signs of infection."),
  rpn("REX-PN","Maternal/Newborn",2,"The nurse assessing a newborn immediately after birth should use the APGAR score, which evaluates:",["Only heart rate and respiration","Appearance (color), Pulse (heart rate), Grimace (reflex irritability), Activity (muscle tone), and Respiration","Only the infant's weight and length","Only the cry of the infant"],1,"APGAR scored at 1 and 5 minutes: Appearance (color: blue/pale=0, body pink/extremities blue=1, all pink=2), Pulse (absent=0, <100=1, >=100=2), Grimace (no response=0, grimace=1, cry=2), Activity (limp=0, some flexion=1, active=2), Respiration (absent=0, slow/irregular=1, good cry=2)."),
  rpn("REX-PN","Infection Control",2,"Standard precautions should be used with:",["Only clients with known infections","All clients regardless of known or suspected infection status","Only immunocompromised clients","Only surgical patients"],0,"Standard precautions apply to ALL patients in ALL settings: assume all blood, body fluids (except sweat), secretions, excretions, non-intact skin, and mucous membranes may contain infectious agents. Includes: hand hygiene, PPE based on exposure risk, safe injection practices, and respiratory hygiene."),
  rpn("REX-PN","Hematological",2,"A client scheduled for surgery should have anticoagulant medications:",["Continued at the same dose through surgery","Held for the appropriate time before surgery as directed by the provider","Doubled before surgery for better protection","Started on the day of surgery"],1,"Preoperative anticoagulant management: warfarin stopped 5 days before (INR < 1.5), DOACs stopped 24-48 hours before (depending on drug and renal function), aspirin may be continued or held based on bleeding risk. Bridging anticoagulation with LMWH may be needed for high-risk patients."),
  rpn("REX-PN","Integumentary",2,"Stage 2 pressure injury is characterized by:",["Full-thickness skin loss with exposed bone or tendon","Partial-thickness loss presenting as a shallow open ulcer or fluid-filled blister","Non-blanchable erythema of intact skin","Deep tissue injury with maroon discoloration"],1,"Stage 2: partial thickness loss of dermis presenting as a shallow open ulcer with red-pink wound bed, no slough. May also present as intact or ruptured serum-filled blister. This stage does NOT include skin tears, tape burns, perineal dermatitis, maceration, or excoriation."),
  rpn("REX-PN","Emergency",2,"In the triage of multiple casualties, the nurse should prioritize:",["The most severely injured patient first regardless of survival chance","Patients who have the best chance of survival with immediate intervention","The quietest patients first","Patients in order of arrival"],1,"Mass casualty triage (START system): Red = immediate (life-threatening but survivable with intervention), Yellow = delayed (serious but can wait), Green = minor (walking wounded), Black = expectant/deceased (unlikely to survive). Maximizes the number of lives saved with available resources."),
  rpn("REX-PN","Geriatrics",2,"Sundowning in a client with dementia refers to:",["Improvement of symptoms in the evening","Increased confusion, agitation, and behavioral disturbances in the late afternoon and evening","Better sleep patterns at night","Morning sickness"],1,"Sundowning: increased confusion, agitation, restlessness, and behavioral disturbances occurring in the late afternoon/evening. Management: maintain consistent daily routine, adequate daytime lighting, reduce stimulation in the evening, avoid caffeine, ensure adequate daytime activity, and night lights."),
  rpn("REX-PN","Community Health",2,"Tertiary prevention refers to:",["Preventing disease before it occurs","Reducing the impact of an existing disease through rehabilitation and preventing complications","Early detection and screening","Immunization programs"],1,"Prevention levels: primary (prevent disease: immunization, health education), secondary (early detection: screening, mammography), tertiary (reduce disability/complications: rehabilitation, chronic disease management, support groups). Tertiary focuses on optimizing function and quality of life."),
  rpn("REX-PN","Nutrition",2,"A client receiving enteral tube feeding should have the head of bed elevated at:",["Flat (0 degrees)","30-45 degrees during and for 30-60 minutes after feeding to prevent aspiration","90 degrees (sitting upright) throughout the day","Trendelenburg position"],1,"HOB elevation reduces aspiration risk by preventing gastric reflux. Maintain 30-45 degrees continuously for continuous feeds, or during and 30-60 minutes after intermittent feeds. Also check residual volumes, tube placement, and maintain oral hygiene."),
  rpn("REX-PN","Wound Care",2,"When packing a wound cavity, the nurse should:",["Pack the wound tightly to prevent any drainage","Moisten the packing material and loosely fill the wound space without packing tightly","Use dry gauze packed firmly into the wound","Leave the wound cavity empty and cover with a dry dressing"],1,"Wound packing: moisten packing material (normal saline or prescribed solution), loosely fill the wound space (tight packing impedes granulation and blood flow), ensure packing contacts all wound surfaces, and avoid overpacking. Cover with appropriate secondary dressing. Document wound assessment."),
  rpn("REX-PN","Cardiovascular",3,"A client with deep vein thrombosis should be monitored for which complication?",["Only leg swelling","Pulmonary embolism (DVT is the most common source of PE)","Myocardial infarction","Stroke"],1,"DVT fragments can travel through the venous system to the pulmonary arteries causing PE (life-threatening). Signs: sudden dyspnea, chest pain, tachycardia, tachypnea, hemoptysis, and hypoxemia. Prevention: anticoagulation, early mobilization, compression stockings, and recognition of PE signs."),
  rpn("REX-PN","Respiratory",2,"Incentive spirometry should be performed by the client:",["Only when reminded by the nurse","Every 1-2 hours while awake to prevent postoperative pulmonary complications","Once daily before discharge","Only during physical therapy sessions"],1,"Incentive spirometry prevents postoperative atelectasis and pneumonia by encouraging sustained maximal inspiratory effort. Technique: exhale normally, seal lips around mouthpiece, inhale slowly and deeply, hold breath for 3-5 seconds. Perform 10 repetitions every 1-2 hours while awake."),
  rpn("REX-PN","Neurological",2,"A client at risk for falls due to postural hypotension should be taught to:",["Stand up quickly to improve alertness","Dangle legs at the bedside before standing and stand slowly with support","Avoid all standing activities","Take extra medication before standing"],1,"Postural hypotension management: sit on the bed edge (dangle) for 1-2 minutes, assess for dizziness, stand slowly using assistive devices or support. Flex feet and legs before standing. Adequate hydration, compression stockings, and medication timing can reduce episodes."),
  rpn("REX-PN","Pharmacology",2,"A client receiving antibiotics should complete the full prescribed course because:",["It is hospital policy","Incomplete courses promote antibiotic resistance and increase the risk of treatment failure","The medication will not work unless all pills are taken","Insurance requires completion"],1,"Incomplete antibiotic courses expose bacteria to sub-therapeutic drug concentrations, promoting survival of resistant organisms. Completing the prescribed course ensures adequate antimicrobial exposure for complete eradication. Exceptions exist (emerging evidence for shorter courses for some infections)."),
  rpn("REX-PN","Mental Health",2,"A client with alcohol use disorder who has been sober for 1 month should be referred to:",["No follow-up is needed after 1 month","Ongoing support groups (AA or similar), counseling, and relapse prevention programs","Only medication management","Inpatient rehabilitation permanently"],1,"Recovery from alcohol use disorder requires ongoing support: mutual support groups (AA, SMART Recovery), individual/group counseling, relapse prevention planning, medication-assisted treatment if appropriate (naltrexone, acamprosate), and addressing social determinants (housing, employment, relationships)."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[Combined-B3] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
